/* 
  Kitchen Scheduling with Minimum Chefs
  - Parallel machine scheduling
  - Feasibility check via min-heap (earliest free chef time)
  - Binary search for minimum m
*/
#include <bits/stdc++.h>
using namespace std;
using ll = long long;

int N;
ll K;
vector<ll> a;

// Check if we can schedule all N tasks within time K using m chefs
bool canFinishWith(int m) {
    // Min-heap of chef free times
    priority_queue<ll, vector<ll>, greater<ll>> pq;
    // Initialize all m chefs free at time 0
    for(int i = 0; i < m; i++) 
        pq.push(0LL);

    for(int i = 0; i < N; i++) {
        ll t = pq.top(); 
        pq.pop();
        ll finish = t + a[i];
        if (finish > K) return false;  // fails to meet deadline
        pq.push(finish);
    }
    return true;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> N >> K;
    a.resize(N);
    ll mx = 0;
    for(int i = 0; i < N; i++){
        cin >> a[i];
        mx = max(mx, a[i]);
    }

    // If a single task exceeds K, impossible
    if (mx > K) {
        cout << -1 << "\n";
        return 0;
    }

    // Binary search over number of chefs in [1, N]
    int lo = 1, hi = N, ans = N+1;
    while(lo <= hi) {
        int mid = (lo + hi) / 2;
        if (canFinishWith(mid)) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }

    if (ans == N+1) ans = -1;
    cout << ans << "\n";
    return 0;
}

